L["Set how long chat stays blocked after login or reload before messages are allowed through."] = "Imposta per quanto tempo la chat rimane bloccata dopo l'accesso o il ricaricamento prima che i messaggi vengano consentiti."
L["Sets the vertical padding between your aura buttons."] = "Imposta la spaziatura verticale tra i pulsanti delle aure."
