L["Text size for friendly player name-only plates. `100%` is the intended default."] = "Dimensione testo per le barre solo-nome dei giocatori amici. `100%` è il valore predefinito previsto."
L["The base size for AzeriteUI nameplates. `100%` is the intended default."] = "La dimensione base per le barre AzeriteUI. `100%` è il valore predefinito previsto."
